func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Safety: Limit memory usage to prevent excessive memory consumption (10MB)
	L.SetMx(10 * 1024 * 1024)

