	// Open only safe standard libraries (base, math, string, table)
	// We avoid io, os, debug, package, and coroutine libraries
	lua.OpenBase(L)
	lua.OpenMath(L)
	lua.OpenString(L)
	lua.OpenTable(L)

	// Remove dangerous functions from the base library to prevent:
	// - Code injection (load, loadfile)
	// - File system access (dofile)
	// - Process manipulation (collectgarbage)
	// - Error handling abuse (pcall, xpcall)
	// - Information leakage (print)
	// - Module loading (require)
	dangerousGlobals := []string{
		"collectgarbage",
		"dofile",
		"load",
		"loadfile",
		"pcall",
		"xpcall",
		"print",
		"require",
		"module",
		"package",
		"io",
		"os",
		"debug",
		"coroutine",
	}

	for _, name := range dangerousGlobals {
		L.SetGlobal(name, lua.LNil)
	}

	// Set memory limit to prevent memory exhaustion attacks (10MB)
	L.SetMx(10 * 1024 * 1024)

	// Set instruction count limit to prevent infinite loops (max 10000 instructions)
	L.SetHook(func(L *lua.LState) {
		L.RaiseError("execution limit exceeded")
	}, lua.LHookCount, 10000)

	// Set execution timeout using context (5 seconds)
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	L.SetContext(ctxTimeout)

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	if ctx != nil {
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	num := float64(result.(lua.LNumber))

	// Validate the result is a finite number (not NaN or Inf)
	if math.IsNaN(num) || math.IsInf(num, 0) {
		return 0, fmt.Errorf("calculate_final_price returned an invalid number")
	}

	// Ensure price is non-negative (business logic constraint)
	if num < 0 {
		return 0, fmt.Errorf("calculate_final_price returned negative price")
	}

	// Set a reasonable upper limit to prevent price manipulation (1 billion)
	const maxPrice = 1e9
