	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64 with type checking
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number, got %s", result.Type().String())
	}

	num, ok := result.(lua.LNumber)
	if !ok {
		return 0, fmt.Errorf("failed to convert result to number")
	}

	f := float64(num)

	// Validate the result is a finite, non-negative number (business logic constraint)
	if math.IsNaN(f) {
		return 0, fmt.Errorf("calculate_final_price returned NaN")
	}
	if math.IsInf(f, 0) {
