import (
	"context"
	"fmt"
	"math"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a context with timeout to prevent infinite loops or long-running scripts
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Create a new Lua state without default libraries to control sandboxing
	L := lua.NewState(lua.Options{
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Set memory limit to 10MB (10240 KB) to prevent memory exhaustion attacks
	L.SetMx(10240)

	// Set execution context for timeout/cancellation support
	L.SetContext(ctxTimeout)

	// Open only safe standard libraries (base, table, string, math)
	// We avoid: io, os, debug, package (require), coroutine
	L.Push(L.NewFunction(lua.OpenBase))
	L.Call(0, 0)
	L.Push(L.NewFunction(lua.OpenTable))
	L.Call(0, 0)
	L.Push(L.NewFunction(lua.OpenString))
	L.Call(0, 0)
	L.Push(L.NewFunction(lua.OpenMath))
	L.Call(0, 0)

	// Remove dangerous functions from the global environment to sandbox the script
	dangerousFuncs := []string{
		"collectgarbage", // Can manipulate GC and cause DoS
		"dofile",         // Can execute arbitrary files
		"load",           // Can load and execute arbitrary Lua code
		"loadfile",       // Can read and execute arbitrary files
		"print",          // Could leak sensitive information to stdout
		"error",          // Can be used to crash the VM or leak stack traces
		"pcall",          // Can catch errors (optional to remove)
		"xpcall",         // Can catch errors with debug info
		"require",        // Can load modules (should not be available in sandbox)
		"module",         // Deprecated module system
	}

	for _, name := range dangerousFuncs {
		L.SetGlobal(name, lua.LNil)
	}

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true, // Catch panics and return as errors
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	num := float64(result.(lua.LNumber))

	// Validate the result is a finite number (not NaN or Infinity)
	if math.IsNaN(num) || math.IsInf(num, 0) {
		return 0, fmt.Errorf("calculate_final_price returned an invalid number")
	}

	return num, nil
}

